(function () {
  let doc, store, win, pWin;
  try {
    doc = window.parent.document;
    store = window.parent.localStorage;
    win = doc.defaultView || window.parent;
    pWin = window.parent || window;
    doc.body;
  } catch (e) {
    doc = document; store = window.localStorage; win = window; pWin = window;
  }

  // ===== 清理旧元素 =====
  ['fp-phone-root', 'fp-phone-style'].forEach(id => doc.getElementById(id)?.remove());
  if (doc._fpEscHandler) doc.removeEventListener('keydown', doc._fpEscHandler);
  if (win._fpClockInterval) clearInterval(win._fpClockInterval); 

  const getVW = () => (doc.documentElement && doc.documentElement.clientWidth) || win.innerWidth;
  const getVH = () => (doc.documentElement && doc.documentElement.clientHeight) || win.innerHeight;
  const noAnim = () =>
    win.matchMedia?.('(prefers-reduced-motion: reduce)').matches ||
    doc.documentElement.classList.contains('st-reduce-motion') ||
    doc.body.classList.contains('st-reduce-motion');

  const CFG = {
    btn: 64, w: 320, h: 560, r: 20, margin: 16, threshold: 4,
    posKey: 'fp-phone-pos-dohna', eyeKey: 'fp-phone-eye-care',
    urlKey: 'fp-phone-api-url', keyKey: 'fp-phone-api-key', modelKey: 'fp-phone-api-model',
    varTimeKey: 'fp-var-time', varDateKey: 'fp-var-date', varYearKey: 'fp-var-year',
    contactsKey: 'fp-phone-contacts-v3' 
  };

  function clamp(v, lo, hi) { return Math.max(lo, Math.min(v, hi)); }
  function clampBtnPos(x, y) { return { x: clamp(x, 0, getVW() - CFG.btn), y: clamp(y, 0, getVH() - CFG.btn) }; }
  function clampPanelPos(x, y) {
    const pw = Math.min(CFG.w, getVW() - CFG.margin * 2); const ph = Math.min(CFG.h, getVH() - CFG.margin * 2);
    return { x: clamp(x, CFG.margin, getVW() - pw - CFG.margin), y: clamp(y, CFG.margin, getVH() - ph - CFG.margin), w: pw, h: ph };
  }

  let isEyeCare = false;
  try { isEyeCare = store.getItem(CFG.eyeKey) === 'true'; } catch (e) {}

  win._fpChats = win._fpChats || {}; 
  win._fpActiveContactId = win._fpActiveContactId || ''; 
  win._fpContacts = [];
  win._fpTempAvatar = '';

  try { 
    let savedC = JSON.parse(store.getItem(CFG.contactsKey)); 
    if (Array.isArray(savedC)) win._fpContacts = savedC;
  } catch (e) {}

  // ===== 🌟 核心引擎 1：深度抓取全域世界书与角色卡 =====
  function fetchLoreFromST(bindKey) {
    let extractedLore = '';
    try {
      let wiText = '';

      // 1. 优先抓取当前角色的独立世界书 (Character Book) - 解决“你是好男孩吗”抓不到设定的痛点
      let charData = null;
      if (window.TavernHelper) charData = window.TavernHelper.getCharData('current');
      if (charData && charData.extensions && charData.extensions.character_book && charData.extensions.character_book.entries) {
        let entries = charData.extensions.character_book.entries;
        let entriesArray = Array.isArray(entries) ? entries : Object.values(entries);
        entriesArray.forEach(e => {
          let keys = Array.isArray(e.keys) ? e.keys : (e.keys ? e.keys.split(',') : []);
          let isMatch = keys.some(k => k.trim() === bindKey || k.trim().includes(bindKey)) || (e.comment && e.comment.includes(bindKey));
          if (isMatch && e.content) wiText += `\n[角色专属设定]: ${e.content}\n`;
        });
      }

      // 2. 抓取全局世界书 (Global World Info)
      if (pWin.world_info && pWin.world_info.entries) {
        Object.values(pWin.world_info.entries).forEach(e => {
          let keys = Array.isArray(e.key) ? e.key : (typeof e.key === 'string' ? e.key.split(',') : []);
          let isMatch = keys.some(k => k.trim() === bindKey || k.trim().includes(bindKey)) || (e.comment && e.comment.includes(bindKey));
          if (isMatch && e.content) wiText += `\n[全局世界书]: ${e.content}\n`;
        });
      }
      if (wiText) extractedLore += wiText;

      // 3. 抓取独立角色卡本体 (如果关联的是其他安装了的角色)
      if (pWin.characters && Array.isArray(pWin.characters)) {
        let char = pWin.characters.find(c => c.name === bindKey || c.name.includes(bindKey));
        if (char) {
          extractedLore += `\n[角色卡本体设定]\n外貌: ${char.description || ''}\n性格: ${char.personality || ''}\n场景: ${char.scenario || ''}\n`;
        }
      }
    } catch(err) { console.error("DohnaPhone 抓取设定失败:", err); }
    return extractedLore.trim();
  }

  // ===== 🌟 核心引擎 2：获取主线现实上下文 =====
  function getMainChatContext() {
    try {
      if (pWin.chat && pWin.chat.length > 0) {
        // 取主界面最后 8 条消息作为“正在发生的事”
        let recent = pWin.chat.slice(-8);
        return recent.map(m => {
          let sender = m.is_user ? (pWin.name1 || 'User') : (m.name || pWin.name2 || 'Char');
          // 剥离 HTML 标签，限制长度防超 Token
          let txt = m.mes.replace(/<[^>]*>?/gm, '').substring(0, 200);
          return `[${sender}]: ${txt}`;
        }).join('\n');
      }
    } catch(e) {}
    return '暂无现实上下文';
  }

  function getSTVar(vName) {
    if (!vName) return '';
    try {
      if (window.TavernHelper && window._) {
        let vars = window.TavernHelper.getVariables({ type: 'message', message_id: 'latest' });
        let val = window._.get(vars, vName);
        if (val !== undefined && val !== null) return String(val);
      }
    } catch (e) {}
    if (typeof pWin.substituteParams === 'function') {
      let res1 = pWin.substituteParams(`{{getvar::${vName}}}`); if (res1 && res1 !== `{{getvar::${vName}}}`) return res1;
      let res2 = pWin.substituteParams(`{{getglobalvar::${vName}}}`); if (res2 && res2 !== `{{getglobalvar::${vName}}}`) return res2;
    }
    return '';
  }

  function updateOSClock() {
    if (!doc.getElementById('fp-phone-root')) return;
    let timeStr = '--:--'; let dateStr = 'V4.5 SYSTEM READY'; let isMvuSynced = false;
    try {
      if (window.Mvu && typeof window._ !== 'undefined') {
        const vars = window.Mvu.getMvuData({ type: 'message', message_id: 'latest' });
        const mvuDateTime = window._.get(vars, 'stat_data.时间.当前日期时间'); 
        const mvuWeekday = window._.get(vars, 'stat_data.时间.当前星期');    
        if (mvuDateTime) {
          const parts = mvuDateTime.split(' ');
          if (parts.length >= 2) { dateStr = parts[0] + (mvuWeekday ? ` ${mvuWeekday}` : ''); timeStr = parts[1]; isMvuSynced = true; }
        }
      }
    } catch (err) {}

    if (!isMvuSynced) {
      let tName = store.getItem(CFG.varTimeKey) || ''; let dName = store.getItem(CFG.varDateKey) || ''; let yName = store.getItem(CFG.varYearKey) || '';
      let tVal = getSTVar(tName); let dVal = getSTVar(dName); let yVal = getSTVar(yName);
      if (tVal && tVal.includes(' ') && !dVal && !dName) { let parts = tVal.split(' '); if (parts.length >= 2) { dVal = parts.slice(0, -1).join(' '); tVal = parts[parts.length - 1]; } }
      let realDate = new Date();
      if (!tVal && !tName) tVal = String(realDate.getHours()).padStart(2, '0') + ':' + String(realDate.getMinutes()).padStart(2, '0');
      if (!dVal && !dName) dVal = `${realDate.getMonth() + 1}月${realDate.getDate()}日`;
      if (!yVal && !yName) yVal = String(realDate.getFullYear());
      timeStr = tVal || '--:--'; let dateArr = []; if (yVal) dateArr.push(yVal); if (dVal) dateArr.push(dVal); dateStr = dateArr.join(' - ') || 'V4.5 SYSTEM READY';
    }
    const timeEl = doc.querySelector('#fp-top-time'); const dateEl = doc.querySelector('#fp-top-date');
    if (timeEl && timeEl.innerText !== timeStr) timeEl.innerText = timeStr;
    if (dateEl && dateEl.innerText !== dateStr) dateEl.innerText = dateStr;
  }

  const st = doc.createElement('style');
  st.id = 'fp-phone-style';
  st.textContent = `
    #fp-phone-root {
      position: fixed; left:0; top:0; width: ${CFG.btn}px; height: ${CFG.btn}px; border-radius: 16px; z-index: 2147483000;
      --dd-pink: #FF007F; --dd-cyan: #00F0FF; --dd-yellow: #FFE600; --dd-dark: #111111; --dd-bg: #F4F4F4;
      background: var(--dd-cyan); border: 4px solid var(--dd-dark); box-shadow: 4px 4px 0px var(--dd-pink);
      overflow: hidden; user-select: none; -webkit-user-select: none; touch-action: none; box-sizing: border-box;
      transition: width .35s cubic-bezier(.175,.885,.32,1.15), height .35s cubic-bezier(.175,.885,.32,1.15),
                  border-radius .35s ease, left .35s cubic-bezier(.175,.885,.32,1.15), top .35s cubic-bezier(.175,.885,.32,1.15),
                  box-shadow .35s ease, background .35s ease, border-color .35s ease, filter .3s;
    }
    #fp-phone-root * { box-sizing: border-box; }
    #fp-phone-root::after { content: ''; position: absolute; inset: 0; pointer-events: none; background: rgba(255, 150, 0, 0.18); mix-blend-mode: multiply; opacity: 0; transition: opacity 0.3s ease; z-index: 9999; border-radius: inherit; }
    #fp-phone-root.fp-eye-care::after { opacity: 1; }
    #fp-phone-root.fp-eye-care { filter: sepia(0.2) brightness(0.92) contrast(0.95); }
    #fp-phone-root.fp-expanded { width: ${CFG.w}px; height: ${CFG.h}px; border-radius: ${CFG.r}px; background-color: var(--dd-bg); background-image: radial-gradient(rgba(17,17,17,0.15) 2px, transparent 2px); background-size: 16px 16px; box-shadow: 8px 8px 0px var(--dd-pink); border-color: var(--dd-dark); }
    #fp-phone-root.fp-dragging { transition: none !important; transform: scale(1.03); cursor: grabbing !important; box-shadow: 12px 12px 0px var(--dd-yellow); }
    #fp-phone-root.fp-no-anim, #fp-phone-root.fp-no-anim.fp-expanded { transition: none !important; }
    .fp-btn { position:absolute; inset:0; display:flex; align-items:center; justify-content:center; cursor: grab; touch-action: none; transition: opacity .2s ease; background: var(--dd-cyan); }
    #fp-phone-root.fp-expanded .fp-btn { opacity: 0; pointer-events: none; }
    .fp-ic { width: 32px; height: 32px; color: var(--dd-dark); transition: transform .2s ease; }
    .fp-btn:hover .fp-ic { transform: scale(1.15) rotate(-10deg); }
    .fp-dot { position:absolute; right:6px; top:6px; width:12px; height:12px; border-radius:50%; background: var(--dd-pink); border: 3px solid var(--dd-dark); }
    .fp-panel { position:absolute; inset:0; display:flex; flex-direction:column; opacity:0; pointer-events:none; transition: opacity .2s ease .1s; }
    #fp-phone-root.fp-expanded .fp-panel { opacity:1; pointer-events:auto; }
    .fp-panel-hd { flex:0 0 auto; height: 50px; display:flex; align-items:center; justify-content:space-between; padding:0 12px 0 16px; cursor: grab; touch-action: none; background: repeating-linear-gradient(-45deg, var(--dd-yellow), var(--dd-yellow) 12px, #FFF066 12px, #FFF066 24px); border-bottom: 4px solid var(--dd-dark); }
    .fp-panel-title { font-size: 18px; letter-spacing: 1px; font-weight: 900; font-style: italic; color: var(--dd-dark); text-shadow: 2px 2px 0px #fff; font-family: "Impact", "Arial Black", sans-serif; }
    .fp-min-btn { appearance:none; background: var(--dd-cyan); color: var(--dd-dark); width: 34px; height: 34px; font-size: 18px; font-weight: 900; cursor: pointer; border-radius: 6px; border: 3px solid var(--dd-dark); box-shadow: 3px 3px 0px var(--dd-pink); transform: skewX(-5deg); display:flex; align-items:center; justify-content:center; transition: all .1s; }
    .fp-min-btn:active { transform: skewX(-5deg) translate(3px, 3px); box-shadow: 0 0 0 transparent; }
    .fp-panel-ct { flex:1 1 auto; overflow:hidden; position:relative; display:flex; flex-direction:column; }
    .fp-home { flex:1; overflow-y:auto; padding:16px; display:flex; flex-direction:column; gap:16px; animation: fade-in 0.3s ease; }
    @keyframes fade-in { from { opacity: 0; transform: translateX(-10px); } to { opacity: 1; transform: translateX(0); } }
    .fp-app-view { flex:1; overflow-y:auto; padding:16px; display:flex; flex-direction:column; animation: slide-in 0.3s ease; min-height:0; }
    @keyframes slide-in { from { opacity: 0; transform: translateX(20px); } to { opacity: 1; transform: translateX(0); } }
    .fp-sb { display:flex; justify-content:space-between; align-items:center; font-size:12px; background:var(--dd-dark); color:#fff; padding:4px 8px; transform:skewX(-5deg); flex-shrink:0; }
    .fp-hero { text-align:center; padding:12px 0; background:var(--dd-pink); color:#fff; border:4px solid var(--dd-dark); box-shadow: 4px 4px 0 var(--dd-cyan); transform: skewX(-2deg); flex-shrink:0; }
    .fp-gr { font-size:26px; font-weight:900; font-style:italic; letter-spacing:2px; text-shadow: 2px 2px 0 var(--dd-dark); }
    .fp-su { font-size:12px; background:var(--dd-yellow); color:var(--dd-dark); display:inline-block; padding:2px 8px; margin-top:6px; border:2px solid var(--dd-dark); max-width: 90%; white-space: nowrap; overflow: hidden; text-overflow: ellipsis; }
    .fp-gd { display:grid; grid-template-columns:repeat(4,1fr); gap:16px 8px; padding:8px 0; flex-shrink:0; }
    .fp-app { display:flex; flex-direction:column; align-items:center; gap:8px; cursor:pointer; }
    .fp-app:active .fp-app-ic { transform: translate(3px,3px) skewX(-3deg); box-shadow: 0 0 0 var(--dd-dark); }
    .fp-app-ic { width:48px; height:48px; border-radius:12px; background:#fff; display:flex; align-items:center; justify-content:center; font-size:20px; font-weight:900; color:var(--dd-dark); border: 3px solid var(--dd-dark); box-shadow: 3px 3px 0 var(--dd-cyan); transition: all .1s; transform: skewX(-3deg); position:relative;}
    .fp-app:nth-child(2n) .fp-app-ic { box-shadow: 3px 3px 0 var(--dd-pink); background:var(--dd-yellow); }
    .fp-app:nth-child(3n) .fp-app-ic { box-shadow: 3px 3px 0 var(--dd-yellow); background:var(--dd-cyan); }
    .fp-app:nth-child(4n) .fp-app-ic { box-shadow: 3px 3px 0 var(--dd-cyan); background:var(--dd-pink); color:#fff;}
    .fp-app span { font-size:12px; font-weight:900; background:var(--dd-dark); color:#fff; padding:2px 6px; transform:skewX(-5deg); }
    .fp-dv { height:4px; background:var(--dd-dark); margin:8px 0; transform:skewX(-5deg); flex-shrink:0; }
    .fp-nt { font-size:12px; line-height:1.6; background:#fff; border:4px solid var(--dd-dark); padding:12px; box-shadow:4px 4px 0 var(--dd-yellow); transform: skewX(-1deg); font-family: "Arial Black", "Microsoft YaHei", sans-serif; font-weight: bold; color: var(--dd-dark); flex-shrink:0;}
    .fp-nt b { color:var(--dd-pink); font-size:16px; font-style:italic; }
    .fp-app-header { display: flex; align-items: center; justify-content: space-between; border-bottom: 4px solid var(--dd-dark); padding-bottom: 12px; margin-bottom: 12px; flex-shrink:0;}
    .fp-back-btn { appearance: none; background: var(--dd-yellow); color: var(--dd-dark); border: 3px solid var(--dd-dark); font-weight: 900; padding: 4px 12px; cursor: pointer; transform: skewX(-5deg); box-shadow: 2px 2px 0 var(--dd-pink); transition: all 0.1s; font-size: 14px; }
    .fp-back-btn:active { transform: skewX(-5deg) translate(2px,2px); box-shadow: 0 0 0 transparent; }
    .fp-app-header span { font-size: 16px; font-weight: 900; font-style: italic; background: var(--dd-dark); color: #fff; padding: 4px 12px; transform: skewX(-5deg); }
    .fp-form-input { width: 100%; padding: 8px 10px; margin-bottom: 12px; border: 3px solid var(--dd-dark); background: #fff; color: var(--dd-dark); font-family: "Arial Black", "Microsoft YaHei", sans-serif; font-weight: bold; font-size: 12px; box-shadow: 3px 3px 0 var(--dd-cyan); transform: skewX(-2deg); outline: none; transition: all 0.1s; flex-shrink:0; }
    .fp-form-input:focus { box-shadow: 3px 3px 0 var(--dd-pink); transform: skewX(-2deg) translate(-1px, -1px); }
    .fp-btn-send { width: 100%; padding: 10px; background: var(--dd-yellow); color: var(--dd-dark); font-weight: 900; font-size: 14px; border: 3px solid var(--dd-dark); cursor: pointer; box-shadow: 4px 4px 0 var(--dd-pink); transform: skewX(-3deg); transition: all 0.1s; text-transform: uppercase; font-style: italic; margin-bottom: 12px; display:flex; align-items:center; justify-content:center; flex-shrink:0;}
    .fp-btn-send:active:not(:disabled) { transform: skewX(-3deg) translate(3px,3px); box-shadow: 0 0 0 transparent; }
    .fp-chat-box { flex:1; overflow-y:auto; display:flex; flex-direction:column; gap:12px; padding-bottom:12px; min-height:0; }
    .fp-chat-box::-webkit-scrollbar { width:6px; }
    .fp-chat-box::-webkit-scrollbar-thumb { background: var(--dd-cyan); border-radius:3px; border:1px solid var(--dd-dark); }
    .fp-bubble { max-width: 85%; padding: 10px 14px; border-radius: 12px; font-size: 13px; font-weight: bold; line-height: 1.5; word-break: break-word; border: 3px solid var(--dd-dark); transform: skewX(-2deg); position: relative; user-select: text; -webkit-user-select: text; flex-shrink:0;}
    .fp-bubble-user { align-self: flex-end; background: var(--dd-yellow); color: var(--dd-dark); border-bottom-right-radius: 2px; box-shadow: -3px 3px 0 var(--dd-cyan); }
    .fp-bubble-ai { align-self: flex-start; background: #fff; color: var(--dd-dark); border-bottom-left-radius: 2px; box-shadow: 3px 3px 0 var(--dd-pink); }
    .fp-bubble-sys { align-self: center; background: var(--dd-dark); color: #fff; border: 2px solid var(--dd-cyan); border-radius: 6px; font-size: 11px; padding: 4px 8px; box-shadow:none; max-width: 90%; text-align:center;}
    .fp-chat-input-area { flex-shrink:0; display:flex; gap:8px; margin-top:8px; padding-top:12px; border-top: 3px dashed var(--dd-dark); }
    .fp-set-item { display: flex; justify-content: space-between; align-items: center; background: #fff; border: 3px solid var(--dd-dark); padding: 12px; margin-bottom: 14px; box-shadow: 3px 3px 0 var(--dd-pink); transform: skewX(-2deg); flex-shrink:0;}
    .fp-set-item span { font-weight: 900; font-size: 14px; color: var(--dd-dark); }
    .fp-eye-btn { appearance: none; background: var(--dd-dark); color: #fff; border: 3px solid var(--dd-dark); font-weight: 900; padding: 6px 16px; cursor: pointer; box-shadow: 2px 2px 0 var(--dd-cyan); transition: all 0.1s; transform: skewX(-5deg); }
    .fp-eye-btn.active { background: var(--dd-cyan); color: var(--dd-dark); box-shadow: 2px 2px 0 var(--dd-pink); }
    .fp-avatar-img { width:40px; height:40px; object-fit:cover; border-radius:50%; border:2px solid var(--dd-dark); box-shadow: 2px 2px 0 var(--dd-cyan); flex-shrink:0; }
    .fp-avatar-placeholder { width:40px; height:40px; background:var(--dd-cyan); border:2px solid var(--dd-dark); border-radius:50%; display:flex; align-items:center; justify-content:center; font-weight:900; font-size:16px; flex-shrink:0; box-shadow: 2px 2px 0 var(--dd-pink);}
    @media (max-width: 480px){ #fp-phone-root.fp-expanded{ width: min(320px, 92vw); max-height: 85vh; } }
    @media (max-height: 700px){ #fp-phone-root.fp-expanded{ height: min(560px, 85vh); } }
  `;
  doc.head.appendChild(st);

  const DEFAULT_HTML = `
    <div class="fp-home">
      <div class="fp-sb"><span id="fp-top-time">--:--</span><span>Dohna OS</span></div>
      <div class="fp-hero"><div class="fp-gr">DohnaPhone</div><div class="fp-su" id="fp-top-date">V4.5 SYSTEM READY</div></div>
      <div class="fp-gd">
        <div class="fp-app" data-app="网域"><div class="fp-app-ic">弋</div><span>网域</span></div>
        <div class="fp-app" data-app="讯息"><div class="fp-app-ic">讯<span id="fp-msg-badge" style="display:none; position:absolute; right:-4px; top:-4px; width:12px; height:12px; background:var(--dd-pink); border-radius:50%; border:2px solid var(--dd-dark);"></span></div><span>讯息</span></div>
        <div class="fp-app" data-app="联络"><div class="fp-app-ic">联</div><span>联络</span></div>
        <div class="fp-app" data-app="设置"><div class="fp-app-ic">设</div><span>设置</span></div>
        <div class="fp-app" data-app="邮箱"><div class="fp-app-ic">邮</div><span>邮箱</span></div>
        <div class="fp-app" data-app="摄像"><div class="fp-app-ic">相</div><span>摄像</span></div>
        <div class="fp-app" data-app="电话"><div class="fp-app-ic">电</div><span>电话</span></div>
        <div class="fp-app" data-app="阅读"><div class="fp-app-ic">阅</div><span>阅读</span></div>
      </div>
      <div class="fp-dv"></div>
      <div class="fp-nt">
        <b>系统提示</b><br><br>
        已搭载 <b style="color:var(--dd-pink)">跨维度设定抓取与主线同步引擎</b>！<br>
        现在小手机不仅能直接提取世界书设定，还会实时记忆主界面的剧情上下文。
      </div>
    </div>`;

  const root = doc.createElement('div');
  root.id = 'fp-phone-root';
  if (noAnim()) root.classList.add('fp-no-anim');
  if (isEyeCare) root.classList.add('fp-eye-care');

  root.innerHTML = `
    <div class="fp-btn"><svg class="fp-ic" viewBox="0 0 24 24" fill="currentColor"><path d="M16 1H8C6.34 1 5 2.34 5 4v16c0 1.66 1.34 3 3 3h8c1.66 0 3-1.34 3-3V4c0-1.66-1.34-3-3-3zm-4 20c-.55 0-1-.45-1-1s.45-1 1-1 1 .45 1 1-.45 1-1 1zm3.5-3H8.5V4h7v14z"/></svg><span class="fp-dot"></span></div>
    <div class="fp-panel"><header class="fp-panel-hd"><span class="fp-panel-title">Dohna OS</span><button class="fp-min-btn" title="最小化">✖</button></header><div class="fp-panel-ct"></div></div>
  `;
  doc.body.appendChild(root);

  const btn = root.querySelector('.fp-btn');
  const hd = root.querySelector('.fp-panel-hd');
  const minBtn = root.querySelector('.fp-min-btn');
  const ct = root.querySelector('.fp-panel-ct');

  function renderHome() { 
    ct.innerHTML = DEFAULT_HTML; 
    updateOSClock(); 
